import React from 'react';
import styles from './LoadingSkeleton.module.css';

export type LoadingSkeletonProps = {
  /** Additional CSS class name(s) */
  className?: string;
  /** Inline style overrides */
  style?: React.CSSProperties;
};

/**
 * LoadingSkeleton — shimmer placeholder for the TrendingProductsWidget carousel.
 *
 * Renders a header placeholder and four card placeholders in a responsive grid.
 * Ported from the CarouselSkeleton in catalog's TrendingProducts feature.
 */
export const LoadingSkeleton = React.forwardRef<HTMLDivElement, LoadingSkeletonProps>(
  function LoadingSkeleton({ className, style }, ref) {
    const rootClass = [styles.root, className].filter(Boolean).join(' ');

    return (
      <div ref={ref} className={rootClass} style={style} data-testid="carousel-skeleton">
        <div className={styles.header} />
        <div className={styles.cards}>
          {[0, 1, 2, 3].map((i) => (
            <div key={i} className={styles.card}>
              <div className={styles.cardContent}>
                <div className={styles.cardTitle} />
                <div className={styles.cardPrice} />
              </div>
            </div>
          ))}
        </div>
      </div>
    );
  },
);

LoadingSkeleton.displayName = 'LoadingSkeleton';
