import React from 'react';
import { Box, Link, Stack, Typography } from '@customink/pigment-react';
import type { UnitPrice } from '../../types';
import styles from './RecommendationsProductCard.module.css';

// Star path inlined from v0 HeartFilledIcon — v0 icons are not on the public API
const STAR_FILLED_PATH =
  'M11.049 2.927c.3-.921 1.603-.921 1.902 0l1.519 4.674a1 1 0 00.95.69h4.915c.969 0 1.371 1.24.588 1.81l-3.976 2.888a1 1 0 00-.363 1.118l1.518 4.674c.3.922-.755 1.688-1.538 1.118l-3.976-2.888a1 1 0 00-1.176 0l-3.976 2.888c-.783.57-1.838-.197-1.538-1.118l1.518-4.674a1 1 0 00-.363-1.118l-3.976-2.888c-.783-.57-.38-1.81.588-1.81h4.914a1 1 0 00.951-.69l1.519-4.674z';

function formatRatingScore(score: number): string {
  const adjusted = score < 1 ? 1 : score;
  return adjusted.toFixed(1);
}

function formatRatingCount(count: number): string | null {
  if (Number.isNaN(count)) return null;
  const cap = 10_000;
  const capped = count > cap ? cap : count;
  const formatted = capped.toLocaleString();
  return `(${count > cap ? `${formatted}+` : formatted})`;
}

function formatPrice(unitPrices: UnitPrice[], quoteQty: number): string | null {
  if (!unitPrices.length) return null;
  const match = unitPrices.find((p) => p.quantity === quoteQty) ?? unitPrices[0];
  return `$${match.price.toFixed(2)}`;
}

export type RecommendationsProductCardProps = {
  name: string;
  linkHref: string;
  imageSrc: string;
  imageSrcSet?: string;
  /** @default name */
  imageAlt?: string;
  minQty: number;
  ratingScore?: number;
  ratingCount?: number;
  defaultUnitPrices: UnitPrice[];
  defaultQuoteQty: number;
  onClick?: React.MouseEventHandler;
  /** Slot rendered as an absolute overlay on the product image (e.g. FavoriteButton) */
  imageOverlay?: React.ReactNode;
  /**
   * Render prop for custom price display.
   * Falls back to a simple formatted price from defaultUnitPrices when omitted.
   */
  renderPriceDetails?: () => React.ReactNode;
  children?: React.ReactNode;
  className?: string;
  style?: React.CSSProperties;
};

/**
 * RecommendationsProductCard — internal molecule for TrendingProductsWidget.
 * Provisional name: will be renamed when DS promotes a public ProductCard atom.
 *
 * NOT exported from the reco public API.
 */
export const RecommendationsProductCard = React.forwardRef<
  HTMLDivElement,
  RecommendationsProductCardProps
>(function RecommendationsProductCard(
  {
    name,
    linkHref,
    imageSrc,
    imageSrcSet,
    imageAlt,
    minQty,
    ratingScore,
    ratingCount,
    defaultUnitPrices,
    defaultQuoteQty,
    onClick,
    imageOverlay,
    renderPriceDetails,
    children,
    className,
    style,
  },
  ref,
) {
  const hasRating =
    ratingScore != null &&
    ratingCount != null &&
    ratingScore > 0 &&
    ratingCount > 0;

  const cardClass = [styles.card, className].filter(Boolean).join(' ');

  return (
    <div ref={ref} className={cardClass} style={style} onClick={onClick}>
      {/* Image area */}
      <a href={linkHref} className={styles.imageLink} tabIndex={-1} aria-hidden="true">
        <div className={styles.imageWrapper}>
          {/* Inset shadow overlay to blend image edges */}
          <div className={styles.imageShadow} aria-hidden="true" />
          <img
            src={imageSrc}
            srcSet={imageSrcSet}
            alt={imageAlt ?? name}
            className={styles.image}
          />
          {imageOverlay}
        </div>
      </a>

      {/* Card content */}
      <div className={styles.content}>
        <a href={linkHref} className={styles.nameLink}>
          <Typography className={styles.name} title={name}>
            {name}
          </Typography>
        </a>

        {hasRating ? <Stack direction="row" className={styles.ratingRow}>
            <svg
              width={20}
              height={20}
              viewBox="0 0 24 24"
              fill="none"
              xmlns="http://www.w3.org/2000/svg"
              aria-hidden="true"
              className={styles.starIcon}
            >
              <path fillRule="evenodd" clipRule="evenodd" d={STAR_FILLED_PATH} fill="currentColor" />
            </svg>
            <Typography className={styles.ratingScore}>
              {formatRatingScore(ratingScore!)}
            </Typography>
            <span className={styles.ratingCount}>
              {formatRatingCount(ratingCount!)}
            </span>
          </Stack> : null}

        <div className={styles.priceArea}>
          {renderPriceDetails
            ? renderPriceDetails()
            : (
              <Typography className={styles.price}>
                {formatPrice(defaultUnitPrices, defaultQuoteQty)}
              </Typography>
            )}
        </div>

        <Typography className={styles.minQty}>
          {minQty === 1 ? 'No Minimum' : `Minimum ${minQty}`}
        </Typography>

        {children}
      </div>
    </div>
  );
});

RecommendationsProductCard.displayName = 'RecommendationsProductCard';
```
